message.content:
@startuml
skinparam classAttributeIconSize 0
skinparam class {
  BackgroundColor #F5F5F5
  BorderColor Black
  ArrowColor Black
}
skinparam stereotypeCBackgroundColor #C8E6C9
skinparam stereotypeCBorderColor Black

class ShoppingCart {
  <<entity>>
  /SubTotal : Currency
  /TaxAmount : Currency
  /DiscountAmount : Currency
  /TotalAmount : Currency
}

class ProductOnCart {
  <<entity>>
  /Price : Currency
  Quantity : Integer
  /Total : Currency
}

class Customer {
  <<C>>
}

class Product {
  <<C>>
}

ShoppingCart "1..1" -- "0..*" ProductOnCart : ProductsOnCart
ProductOnCart "0..*" -- "1..1" ShoppingCart : ShoppingCart
ShoppingCart "0..*" --> "1..1" Customer : Customer
ProductOnCart "0..*" --> "1..1" Product : Product

@enduml
